SELECT ?drug ?drugLabel ?brand ?brandLabel ?side_effect ?side_effectLabel WHERE {
  ?drug wdt:P31 wd:Q444925.
  ?drug rdfs:label ?drugLabel. FILTER (LANG(?drugLabel) = 'en').
  OPTIONAL { ?brand wdt:P127 ?drug.
             ?brand rdfs:label ?brandLabel. FILTER (LANG(?brandLabel) = 'en'). }
  OPTIONAL { ?drug wdt:P2027 ?side_effect.
             ?side_effect rdfs:label ?side_effectLabel. FILTER (LANG(?side_effectLabel) = 'en'). }
} LIMIT 10

